                "gitBranch",
                "slug",
            ],
        ),
    ])
}

/// Look up a dotted path like "message.usage.speed" in a serde_json::Value.
fn value_at_path<'a>(val: &'a Value, path: &str) -> Option<&'a Value> {
    let mut current = val;
    for segment in path.split('.') {
        current = current.get(segment)?;
    }
    // Return None for JSON null (serde Option fields serialize as null when absent)
    if current.is_null() {
        None
    } else {
        Some(current)
    }
}

#[test]
fn all_optional_fields_seen() {
    let expected = optional_fields_by_type();
    // Track (record_type, field) -> count of non-null occurrences
    let mut seen: HashMap<(&str, &str), usize> = HashMap::new();

    for path in TEST_FILES {
        let file = File::open(path).expect("test file should exist");
        let reader = BufReader::new(file);
        for line in reader.lines() {
            let line = line.unwrap();
            if line.trim().is_empty() {
                continue;
            }
            let val: Value = match serde_json::from_str(&line) {
                Ok(v) => v,
                Err(_) => continue,
            };
            let record_type = match val.get("type").and_then(|t| t.as_str()) {
                Some(t) => t,
                None => continue,
            };
            if let Some(fields) = expected.get(record_type) {
                for field in fields {
                    if value_at_path(&val, field).is_some() {
                        // Safe: record_type comes from the static expected keys
                        let key = (record_type, *field);
                        *seen.entry(key).or_insert(0) += 1;
                    }
                }
            }
        }
    }

    let mut never_seen = Vec::new();
    for (record_type, fields) in &expected {
        for field in fields {
            if !seen.contains_key(&(*record_type, *field)) {
                never_seen.push(format!("{record_type}.{field}"));
            }
        }
    }
    never_seen.sort();
    assert!(
        never_seen.is_empty(),
        "Option fields never seen as Some in test data: {never_seen:?}"
    );
}

