        for path in TEST_FILES {
            deserialize_file_collecting(path, Some(&mut seen));
        }
        let expected: HashSet<String> =
            Record::all_labels().iter().map(|s| s.to_string()).collect();
        let missing: Vec<_> = expected.difference(&seen).collect();
        assert!(
            missing.is_empty(),
