mod tests {
    use super::*;
    use std::collections::HashSet;
    use std::fs::File;
    use std::io::{BufRead, BufReader};

    const TEST_FILES: &[&str] = &[
        "data/31ba272b-f7c2-436b-a017-269e27a64d07.jsonl",
        "data/997afb98-c6aa-4f4a-92ac-a841e040414b.jsonl",
